// api/v3/handlers/addons/get.go
package addons

import (
	"context"

	apiv3 "github.com/openmeterio/openmeter/api/v3"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport/apierrors"
)

type GetAddonRequest = apiv3.GetAddonRequestObject
type GetAddonResponse = apiv3.GetAddonResponseObject

func (h *handler) GetAddon(ctx context.Context, req GetAddonRequest) (GetAddonResponse, error) {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r GetAddonRequest) (GetAddonResponse, error) {
			a, err := h.addonService.GetAddon(ctx, addon.GetAddonInput{Namespace: r.Namespace, ID: r.AddonId})
			if err != nil {
				return nil, err
			}
			return apiv3.GetAddon200JSONResponse(ToAPIAddon(*a)), nil
		},
		func(ctx context.Context, r *http.Request) (GetAddonRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil {
				return GetAddonRequest{}, err
			}
			return GetAddonRequest{Namespace: ns, AddonId: chi.URLParam(r, "addonId")}, nil
		},
		ttptransport.JSONResponseEncoder[GetAddonResponse],
		httptransport.AppendOptions(h.options, httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder())),
	).ServeHTTP
}
